function readJsonl(rel) {
  const text = readFileSync(join(root, rel), 'utf8').trim();
  return text ? text.split(/\r?\n/).filter(Boolean).map((line) => JSON.parse(line)) : [];
}

function stableHash(candidate) {
  const hashBase = {
    id: candidate.id,
    studentStem: candidate.studentStem,
    options: candidate.options,
    correctOptionId: candidate.correctOptionId,
    knowledgePointIds: candidate.knowledgePointIds,
    construction_note_en: candidate.construction_note_en,
    knowledge_link_map: candidate.knowledge_link_map
  };
  return `sha256:${createHash('sha256').update(JSON.stringify(hashBase)).digest('hex')}`;
}

function weightsFor(kpIds) {
  const base = kpIds.map((id, index) => {
    if (index === 0) return 0.4;
    if (index === 1) return 0.25;
    if (index === 2) return 0.2;
    return 0.15 / Math.max(1, kpIds.length - 3);
  });
  const total = base.reduce((sum, value) => sum + value, 0);
  return base.map((value) => Number((value / total).toFixed(3)));
}

function profileFor(repair) {
  const profile = sectionProfiles[repair.sectionId ?? defaultSectionId];
  if (!profile) throw new Error(`${repair.id}: unknown section profile ${repair.sectionId}`);
  return profile;
}

function buildQkl(questionId, kpIds, profile) {
  const weights = weightsFor(kpIds);
  return kpIds.map((knowledgePointId, index) => ({
    questionId,
    knowledgePointId,
    linkType: index === 0 ? 'primary' : 'supporting',
    role: index === 0 ? 'primary' : 'supporting',
    weight: weights[index],
    evidenceMode: 'mpcq_repaired_candidate',
    confidence: 'candidate',
    sourceBatch: profile.importBatchId,
    sourcePath: 'sanitized-ocr-candidate://questions/intake-candidates.jsonl',
    sourceEvidenceStatus: 'reviewed_not_runtime_source_atom',
    sourceAtomId: profile.sourceAtomId,
    reason: `Repaired MPCQ candidate links ${questionId} to ${knowledgePointId}; runtime activation remains blocked.`
  }));
}

function buildCertification(repair, profile) {
  const sourceAtom = sourceAtomById.get(profile.sourceAtomId);
  return {
    source_key: profile.sourceAtomId,
    stella_chapter: chapterLabelFor(profile.sectionId),
    stella_subchapter: profile.sectionId,
    claimed_stella_pages: sourceAtom?.evidenceRefIds?.map(shortEvidenceRef) ?? [],
    sourceClaimIds: [profile.sourceClaimId],
    bookLocationIds: [profile.bookLocationId],
    ocrVerificationStatus: 'reviewed_not_runtime_source_atom_no_raw_excerpt',
    testedConcepts: repair.kps.map((id) => kpById.get(id)?.label ?? id),
    missingConcepts: [],
    runtimeEligible: false
  };
}

function chapterLabelFor(sectionId) {
  const match = sectionId.match(/kap(\d+)/);
  return match ? `K${match[1]}` : 'K1';
}

function shortEvidenceRef(evidenceRefId) {
  const match = evidenceRefId.match(/-s(\d+)$/);
  return match ? `s.${match[1]}` : evidenceRefId;
}

function buildCandidate(original, repair) {
  for (const id of repair.kps) {
    if (!kpById.has(id)) throw new Error(`${repair.id}: missing KP ${id}`);
  }
  const profile = profileFor(repair);
  const options = ['A', 'B', 'C', 'D'].map((id) => ({ id, text: repair.options[id] }));
  const candidate = {
    ...original,
    formatNumber: 4,
    mpcqFormat: 'singapore-pure-text',
    mpcqReviewStatus: 'repaired_pending_review',
    studentStem: repair.stem,
    options,
    correctOptionId: repair.correct,
    distractorRationales: Object.entries(repair.distractors).map(([optionId, rationale]) => ({ optionId, rationale })),
    solution: repair.solution ?? `Rätt svar är ${repair.correct}. Frågan kräver att eleven väger data i scenariot mot utveckling, mångfald, biologisk funktion och rimliga felmodeller.`,
    publicSanitizedSourceSummary: repair.publicSanitizedSourceSummary ?? profile.publicSanitizedSourceSummary,
    bookLocationIds: [profile.bookLocationId],
    sourceClaimIds: [profile.sourceClaimId],
    knowledgePointIds: repair.kps,
    questionKnowledgeLinks: buildQkl(repair.id, repair.kps, profile),
    runtimeProjection: {
      typ: repair.typ,
      niva: repair.level,
      delkapitel: profile.delkapitel,
      stella: profile.stella
    },
    difficultyLevel: repair.level,
    enabledLevels: [`niva-${repair.level}`],
    skillTags: repair.tags,
    abilityTags: ['dataresonemang', 'höginferens', 'begreppslig-förståelse'],
    techniqueTags: ['mpcq', 'singapore-pure-text', 'distraktoranalys', 'shortcut-check'],
    importBatchId: profile.importBatchId,
    createdFromSourceId: profile.sourceAtomId,
    ocr_verification: buildCertification(repair, profile),
    sourceCertification: buildCertification(repair, profile),
    construction_note_en: repair.note,
    knowledge_link_map: repair.links.map(([cue, requiredInference, whyNeeded, kpId]) => ({
      cue,
      requiredInference,
      whyNeeded,
      knowledgePointId: kpId
    })),
    remediation_map: repair.links.map(([cue, requiredInference, whyNeeded, kpId], index) => ({
      failedLink: `L${index + 1}`,
      knowledgePointId: kpId,
      remediation: `Återkoppla till ${kpById.get(kpId)?.label ?? kpId}: eleven behöver koppla ${cue} till ${requiredInference}.`
    })),
    shortcut_check: {
      textKeywordEcho: 'checked_no_correct_option_keyword_echo_intended',
      oneFactSolvable: false,
      answerLengthCue: false,
      decorativeVisualRisk: false,
      requiresIndependentLinks: repair.links.length,
      reviewerNote: 'Pure text format is allowed here because the stem contains compact scenario or numeric data; the answer requires multiple inferences.'
    },
    mpcqRubric: {
      estimatedScore: repair.links.length >= 4 ? 17 : 16,
      passThreshold: 15,
      goldThreshold: 18,
      status: 'candidate_pass_pending_external_review'
    }
  };
  candidate.contentHash = stableHash(candidate);
  return candidate;
}

const positionalArgs = process.argv.slice(2).filter((arg) => !arg.startsWith('--'));
if (positionalArgs.length > 2) {
  throw new Error(`Expected at most 2 positional args: offset count. Got ${positionalArgs.length}.`);
}

function readPositiveInt(name, fallback, positionalIndex) {
  const cliPrefix = `--${name}=`;
  const cliValue = process.argv.find((arg) => arg.startsWith(cliPrefix))?.slice(cliPrefix.length);
  const positionalValue = positionalArgs[positionalIndex];
  if (cliValue !== undefined && positionalValue !== undefined && cliValue !== positionalValue) {
    throw new Error(`Conflicting ${name} values: --${name}=${cliValue} and positional ${positionalValue}`);
  }
  const rawValue = cliValue ?? positionalValue ?? process.env[`MPCQ_${name.toUpperCase()}`];
  if (rawValue === undefined || rawValue === '') return fallback;
  const parsed = Number(rawValue);
  if (!Number.isInteger(parsed) || parsed < 0) {
    throw new Error(`${name} must be a non-negative integer, got ${rawValue}`);
  }
  return parsed;
}

const batchOffset = readPositiveInt('offset', 0, 0);
const batchCount = readPositiveInt('count', 3, 1);
const idsArg = process.argv.find((arg) => arg.startsWith('--ids='))?.slice('--ids='.length);
const selectedIds = idsArg ? idsArg.split(',').map((id) => id.trim()).filter(Boolean) : [];
const activeRepairs = selectedIds.length > 0
  ? selectedIds.map((id) => {
    const repair = repairs.find((item) => item.id === id);
    if (!repair) throw new Error(`Unknown repair id: ${id}`);
    return repair;
  })
  : repairs.slice(batchOffset, batchOffset + batchCount);
if (activeRepairs.length > 3) {
  throw new Error(`Max 3 repairs per batch. Requested ${activeRepairs.length}.`);
}
if (selectedIds.length === 0 && activeRepairs.length !== batchCount) {
  throw new Error(`Requested ${batchCount} repairs from offset ${batchOffset}, found ${activeRepairs.length}`);
}
const repairById = new Map(activeRepairs.map((repair) => [repair.id, repair]));
let repairedCount = 0;
const nextCandidates = candidates.map((candidate) => {
  const repair = repairById.get(candidate.id);
  if (!repair) return candidate;
  repairedCount += 1;
  return buildCandidate(candidate, repair);
});

if (repairedCount !== activeRepairs.length) {
  throw new Error(`Expected ${activeRepairs.length} repairs, applied ${repairedCount}`);
}

const tmpCandidatesPath = `${candidatesPath}.tmp`;
writeFileSync(tmpCandidatesPath, nextCandidates.map((candidate) => JSON.stringify(candidate)).join('\n') + '\n');
renameSync(tmpCandidatesPath, candidatesPath);
console.log(JSON.stringify({ ok: true, repairedCount, ids: activeRepairs.map((repair) => repair.id) }, null, 2));
